import React, { useEffect, useMemo, useState } from 'react'
import { Link } from 'react-router-dom'
import { motion } from 'motion/react'
import { getProducts } from '../services/productService'

const listVariants = {
  hidden: {},
  visible: {
    transition: {
      staggerChildren: 0.06,
      delayChildren: 0.04,
    },
  },
}

const itemVariants = {
  hidden: { opacity: 0, y: 12 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.28, ease: 'easeOut' },
  },
}

function formatPrice(value) {
  return new Intl.NumberFormat('vi-VN', {
    style: 'currency',
    currency: 'VND',
    maximumFractionDigits: 0,
  }).format(value || 0)
}

function ProductSection() {
  const [products, setProducts] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')

  const apiUrl = useMemo(() => 'http://localhost:8080/products', [])

  useEffect(() => {
    let cancelled = false

    async function loadProducts() {
      setLoading(true)
      setError('')

      try {
        const items = await getProducts()

        if (!cancelled) {
          setProducts(items)
        }
      } catch (err) {
        if (!cancelled) {
          setError(err?.message || 'Đã có lỗi khi tải sản phẩm')
          setProducts([])
        }
      } finally {
        if (!cancelled) {
          setLoading(false)
        }
      }
    }

    loadProducts()

    return () => {
      cancelled = true
    }
  }, [apiUrl])

  return (
    <section id="products" className="mt-14">
      <div className="flex flex-wrap items-end justify-between gap-3">
        <div>
          <p className="text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">Sản phẩm</p>
          <h2 className="mt-2 text-3xl font-semibold tracking-tight text-zinc-900">Danh sách sản phẩm mới nhất</h2>
        </div>
        <p className="text-sm text-zinc-600">Nguồn dữ liệu từ API `localhost:8080/products`</p>
      </div>

      {loading && (
        <div className="mt-6 rounded-2xl border border-zinc-200 bg-white p-6 text-sm text-zinc-600">
          Đang tải sản phẩm...
        </div>
      )}

      {!loading && error && (
        <div className="mt-6 rounded-2xl border border-red-200 bg-red-50 p-6 text-sm text-red-700">
          Không thể tải sản phẩm: {error}
        </div>
      )}

      {!loading && !error && products.length === 0 && (
        <div className="mt-6 rounded-2xl border border-zinc-200 bg-white p-6 text-sm text-zinc-600">
          Chưa có sản phẩm nào để hiển thị.
        </div>
      )}

      {!loading && !error && products.length > 0 && (
        <motion.div
          variants={listVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: 0.2 }}
          className="mt-6 grid gap-4 md:grid-cols-2"
        >
          {products.map((product) => (
            <motion.article
              key={product.id}
              variants={itemVariants}
              className="overflow-hidden rounded-2xl border border-zinc-200 bg-white"
            >
              <div className="h-44 bg-zinc-100">
                {product.imageUrl ? (
                  <img
                    src={product.imageUrl}
                    alt={product.name}
                    className="h-full w-full object-cover"
                  />
                ) : (
                  <div className="flex h-full items-center justify-center bg-gradient-to-br from-zinc-200 to-zinc-100 text-sm font-semibold text-zinc-500">
                    Chưa có ảnh sản phẩm
                  </div>
                )}
              </div>

              <div className="p-5">
                <div className="flex items-start justify-between gap-3">
                  <h3 className="text-lg font-semibold text-zinc-900">{product.name}</h3>
                  <span className="rounded-full border border-zinc-200 bg-zinc-100 px-2.5 py-1 text-[11px] font-semibold uppercase tracking-[0.15em] text-zinc-600">
                    {product.status}
                  </span>
                </div>

                <p className="mt-2 line-clamp-2 text-sm text-zinc-600">{product.description}</p>

                <div className="mt-4 grid grid-cols-2 gap-2 text-sm text-zinc-600">
                  <p>Danh mục: <span className="font-medium text-zinc-900">{product.categoryName}</span></p>
                  <p>Kho: <span className="font-medium text-zinc-900">{product.stock}</span></p>
                  <p>Người bán: <span className="font-medium text-zinc-900">{product.sellerUsername}</span></p>
                  <p>ID: <span className="font-medium text-zinc-900">#{product.id}</span></p>
                </div>

                <div className="mt-5 flex items-center justify-between">
                   <p className="text-xl font-semibold text-zinc-900">{formatPrice(product.price)}</p>
                   <Link
                     to={`/products/${product.id}`}
                     className="rounded-full bg-zinc-900 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-white hover:bg-zinc-700"
                   >
                     Xem chi tiết
                   </Link>
                 </div>
              </div>
            </motion.article>
          ))}
        </motion.div>
      )}
    </section>
  )
}

export default ProductSection

import React, { useEffect, useMemo, useState } from 'react'
import { Link } from 'react-router-dom'
import { motion } from 'motion/react'
import { getProducts } from '../services/productService'
import { getCategories } from '../services/categoryService'

const listVariants = {
  hidden: {},
  visible: {
    transition: {
      staggerChildren: 0.06,
      delayChildren: 0.04,
    },
  },
}

const itemVariants = {
  hidden: { opacity: 0, y: 12 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.28, ease: 'easeOut' },
  },
}

function formatPrice(value) {
  return new Intl.NumberFormat('vi-VN', {
    style: 'currency',
    currency: 'VND',
    maximumFractionDigits: 0,
  }).format(value || 0)
}

function normalizeText(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim()
}

function ProductSection() {
  const [products, setProducts] = useState([])
  const [categories, setCategories] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [searchTerm, setSearchTerm] = useState('')
  const [selectedCategory, setSelectedCategory] = useState('all')
  const [stockFilter, setStockFilter] = useState('all')
  const [minPrice, setMinPrice] = useState('')
  const [maxPrice, setMaxPrice] = useState('')
  const [priceSort, setPriceSort] = useState('default')
  const [isFilterPanelOpen, setIsFilterPanelOpen] = useState(false)

  useEffect(() => {
    let cancelled = false

    async function loadProducts() {
      setLoading(true)
      setError('')

      try {
        const items = await getProducts()

        if (!cancelled) {
          setProducts(items)
        }
      } catch (err) {
        if (!cancelled) {
          setError(err?.message || 'Đã có lỗi khi tải sản phẩm')
          setProducts([])
        }
      } finally {
        if (!cancelled) {
          setLoading(false)
        }
      }
    }

    loadProducts()

    return () => {
      cancelled = true
    }
  }, [])

  useEffect(() => {
    let cancelled = false

    async function loadCategories() {
      try {
        const items = await getCategories()
        if (!cancelled) {
          setCategories(items)
        }
      } catch {
        if (!cancelled) {
          setCategories([])
        }
      }
    }

    loadCategories()

    return () => {
      cancelled = true
    }
  }, [])

  const filteredProducts = useMemo(() => {
    const keyword = normalizeText(searchTerm)
    const min = Number(minPrice)
    const max = Number(maxPrice)
    const hasMin = Number.isFinite(min) && min > 0
    const hasMax = Number.isFinite(max) && max > 0

    const result = products.filter((product) => {
      const productName = normalizeText(product?.name)
      const matchName = !keyword || productName.includes(keyword)

      const categoryId = String(product?.categoryId || '')
      const matchCategory = selectedCategory === 'all' || categoryId === selectedCategory

      const stock = Number(product?.stock || 0)
      const matchStock =
        stockFilter === 'all' ||
        (stockFilter === 'inStock' && stock > 0) ||
        (stockFilter === 'outOfStock' && stock <= 0) ||
        (stockFilter === 'lowStock' && stock > 0 && stock <= 10)

      const price = Number(product?.price || 0)
      const matchMinPrice = !hasMin || price >= min
      const matchMaxPrice = !hasMax || price <= max

      return matchName && matchCategory && matchStock && matchMinPrice && matchMaxPrice
    })

    if (priceSort === 'asc') {
      result.sort((a, b) => Number(a?.price || 0) - Number(b?.price || 0))
    }

    if (priceSort === 'desc') {
      result.sort((a, b) => Number(b?.price || 0) - Number(a?.price || 0))
    }

    return result
  }, [products, searchTerm, selectedCategory, stockFilter, minPrice, maxPrice, priceSort])

  return (
    <section id="products" className="mt-14">
      <div className="flex flex-wrap items-end justify-between gap-3">
        <div>
          <p className="text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">Sản phẩm</p>
          <h2 className="mt-2 text-3xl font-semibold tracking-tight text-zinc-900">Danh sách sản phẩm mới nhất</h2>
        </div>
        <div className="flex items-center gap-2">
          <p className="text-sm text-zinc-600">Nguồn dữ liệu từ API `localhost:8080/products`</p>
          <button
            type="button"
            onClick={() => setIsFilterPanelOpen((prev) => !prev)}
            className="rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900"
          >
            {isFilterPanelOpen ? 'Ẩn bộ lọc' : 'Bộ lọc'}
          </button>
        </div>
      </div>

      {isFilterPanelOpen && (
      <div className="mt-4 rounded-2xl border border-zinc-200 bg-white p-4">
        <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3">
          <div className="md:col-span-2 lg:col-span-3">
            <label htmlFor="product-search" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Tìm kiếm theo tên sản phẩm
            </label>
            <input
              id="product-search"
              type="text"
              value={searchTerm}
              onChange={(event) => setSearchTerm(event.target.value)}
              placeholder="Nhập tên sản phẩm..."
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-4 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            />
          </div>

          <div>
            <label htmlFor="category-filter" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Danh mục
            </label>
            <select
              id="category-filter"
              value={selectedCategory}
              onChange={(event) => setSelectedCategory(event.target.value)}
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            >
              <option value="all">Tất cả danh mục</option>
              {categories.map((category) => (
                <option key={category.id} value={String(category.id)}>
                  {category.name}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label htmlFor="stock-filter" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Số lượng
            </label>
            <select
              id="stock-filter"
              value={stockFilter}
              onChange={(event) => setStockFilter(event.target.value)}
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            >
              <option value="all">Tất cả</option>
              <option value="inStock">Còn hàng</option>
              <option value="outOfStock">Hết hàng</option>
              <option value="lowStock">Sắp hết (1-10)</option>
            </select>
          </div>

          <div>
            <label htmlFor="price-sort" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Giá tiền
            </label>
            <select
              id="price-sort"
              value={priceSort}
              onChange={(event) => setPriceSort(event.target.value)}
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            >
              <option value="default">Mặc định</option>
              <option value="asc">Thấp đến cao</option>
              <option value="desc">Cao đến thấp</option>
            </select>
          </div>

          <div>
            <label htmlFor="min-price" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Giá từ
            </label>
            <input
              id="min-price"
              type="number"
              min="0"
              value={minPrice}
              onChange={(event) => setMinPrice(event.target.value)}
              placeholder="0"
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            />
          </div>

          <div>
            <label htmlFor="max-price" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Giá đến
            </label>
            <input
              id="max-price"
              type="number"
              min="0"
              value={maxPrice}
              onChange={(event) => setMaxPrice(event.target.value)}
              placeholder="99999999"
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            />
          </div>
        </div>
      </div>
      )}

      {loading && (
        <div className="mt-6 rounded-2xl border border-zinc-200 bg-white p-6 text-sm text-zinc-600">
          Đang tải sản phẩm...
        </div>
      )}

      {!loading && error && (
        <div className="mt-6 rounded-2xl border border-red-200 bg-red-50 p-6 text-sm text-red-700">
          Không thể tải sản phẩm: {error}
        </div>
      )}

      {!loading && !error && products.length === 0 && (
        <div className="mt-6 rounded-2xl border border-zinc-200 bg-white p-6 text-sm text-zinc-600">
          Chưa có sản phẩm nào để hiển thị.
        </div>
      )}

      {!loading && !error && products.length > 0 && filteredProducts.length === 0 && (
        <div className="mt-6 rounded-2xl border border-amber-200 bg-amber-50 p-6 text-sm text-amber-800">
          Không tìm thấy sản phẩm phù hợp với từ khóa "{searchTerm.trim()}".
        </div>
      )}

      {!loading && !error && filteredProducts.length > 0 && (
        <motion.div
          variants={listVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: 0.2 }}
          className="mt-6 grid gap-4 md:grid-cols-2"
        >
          {filteredProducts.map((product) => (
            <motion.article
              key={product.id}
              variants={itemVariants}
              className="overflow-hidden rounded-2xl border border-zinc-200 bg-white"
            >
              <div className="h-44 bg-zinc-100">
                {product.imageUrl ? (
                  <img
                    src={product.imageUrl}
                    alt={product.name}
                    className="h-full w-full object-cover"
                  />
                ) : (
                  <div className="flex h-full items-center justify-center bg-gradient-to-br from-zinc-200 to-zinc-100 text-sm font-semibold text-zinc-500">
                    Chưa có ảnh sản phẩm
                  </div>
                )}
              </div>

              <div className="p-5">
                <div className="flex items-start justify-between gap-3">
                  <h3 className="text-lg font-semibold text-zinc-900">{product.name}</h3>
                  <span className="rounded-full border border-zinc-200 bg-zinc-100 px-2.5 py-1 text-[11px] font-semibold uppercase tracking-[0.15em] text-zinc-600">
                    {product.status}
                  </span>
                </div>

                <p className="mt-2 line-clamp-2 text-sm text-zinc-600">{product.description}</p>

                <div className="mt-4 grid grid-cols-2 gap-2 text-sm text-zinc-600">
                  <p>Danh mục: <span className="font-medium text-zinc-900">{product.categoryName}</span></p>
                  <p>Kho: <span className="font-medium text-zinc-900">{product.stock}</span></p>
                  <p>Người bán: <span className="font-medium text-zinc-900">{product.sellerUsername}</span></p>
                  <p>ID: <span className="font-medium text-zinc-900">#{product.id}</span></p>
                </div>

                <div className="mt-5 flex items-center justify-between">
                   <p className="text-xl font-semibold text-zinc-900">{formatPrice(product.price)}</p>
                   <Link
                     to={`/products/${product.id}`}
                     className="rounded-full bg-zinc-900 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-white hover:bg-zinc-700"
                   >
                     Xem chi tiết
                   </Link>
                 </div>
              </div>
            </motion.article>
          ))}
        </motion.div>
      )}
    </section>
  )
}

export default ProductSection

import React, { useEffect, useMemo, useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import toast from 'react-hot-toast'
import { getCurrentUserDetail, updateCurrentUser } from '../services/authService'
import { clearAuth, getAuthSession } from '../services/sessionService'

function getInitials(name) {
  if (!name) return 'U'
  const parts = name.trim().split(/\s+/).filter(Boolean)
  if (parts.length === 0) return 'U'
  if (parts.length === 1) return parts[0].slice(0, 1).toUpperCase()
  return `${parts[0][0]}${parts[parts.length - 1][0]}`.toUpperCase()
}

function UserProfilePage() {
  const [session, setSession] = useState(() => getAuthSession())
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [userDetail, setUserDetail] = useState(null)
  const [isEditing, setIsEditing] = useState(false)
  const [saving, setSaving] = useState(false)
  const [form, setForm] = useState({
    fullName: '',
    email: '',
    phone: '',
    address: '',
  })
  const navigate = useNavigate()

  useEffect(() => {
    if (!session?.token) {
      navigate('/login', { replace: true })
      return
    }

    async function loadUserDetail() {
      setLoading(true)
      setError('')

      try {
        const detail = await getCurrentUserDetail()
        setUserDetail(detail)
        setForm({
          fullName: detail?.fullName || '',
          email: detail?.email || '',
          phone: detail?.phone || '',
          address: detail?.address || '',
        })
      } catch (err) {
        setError(err?.message || 'Không thể tải thông tin tài khoản')
      } finally {
        setLoading(false)
      }
    }

    loadUserDetail()
  }, [navigate, session?.token])

  const user = useMemo(() => {
    return userDetail || session?.user || null
  }, [session?.user, userDetail])

  const displayName = user?.fullName || user?.username || 'Tài khoản'
  const avatarUrl = user?.avatarUrl

  const missingFields = useMemo(() => {
    const checks = [
      { key: 'fullName', label: 'Họ tên' },
      { key: 'email', label: 'Email' },
      { key: 'phone', label: 'Số điện thoại' },
      { key: 'address', label: 'Địa chỉ' },
    ]

    return checks
      .filter(({ key }) => {
        const value = user?.[key]
        if (value === null || value === undefined) return true
        if (typeof value !== 'string') return false
        const normalized = value.trim()
        return normalized.length === 0 || normalized === '-'
      })
      .map(({ label }) => label)
  }, [user])

  const isProfileIncomplete = missingFields.length > 0

  const handleLogout = () => {
    clearAuth()
    toast.success('Đã đăng xuất')
    navigate('/login')
  }

  const handleUpdateInfo = () => {
    setIsEditing(true)
  }

  const handleChange = (event) => {
    const { name, value } = event.target
    setForm((prev) => ({ ...prev, [name]: value }))
  }

  const handleCancelEdit = () => {
    setForm({
      fullName: user?.fullName || '',
      email: user?.email || '',
      phone: user?.phone || '',
      address: user?.address || '',
    })
    setIsEditing(false)
  }

  const handleSubmitUpdate = async (event) => {
    event.preventDefault()

    const payload = {
      fullName: form.fullName.trim(),
      email: form.email.trim(),
      phone: form.phone.trim(),
      address: form.address.trim(),
    }

    if (!payload.fullName || !payload.email || !payload.phone || !payload.address) {
      toast.error('Vui lòng cập nhật thông tin')
      return
    }

    setSaving(true)
    try {
      const updated = await updateCurrentUser(payload)
      setUserDetail((prev) => ({ ...prev, ...updated }))
      setSession((prev) => {
        if (!prev) return prev
        return {
          ...prev,
          user: {
            ...(prev.user || {}),
            ...updated,
          },
        }
      })
      setIsEditing(false)
      toast.success('Cập nhật thông tin thành công')
    } catch (err) {
      toast.error(err?.message || 'Không thể cập nhật thông tin')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="min-h-screen bg-[linear-gradient(180deg,#f7f7f4_0%,#f4f4ef_45%,#ffffff_100%)] px-6 py-10">
      <div className="mx-auto w-full max-w-5xl">
        <header className="mb-8 flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">SplitGo</p>
            <h1 className="mt-2 text-3xl font-semibold tracking-tight text-zinc-900">Thông tin người dùng</h1>
          </div>
          <div className="flex items-center gap-3">
            <Link to="/products" className="rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900">
              Về sản phẩm
            </Link>
            {isProfileIncomplete && (
              <button
                onClick={handleUpdateInfo}
                className="rounded-full border border-amber-300 bg-amber-50 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-amber-800 hover:border-amber-500"
              >
                Cập nhật thông tin
              </button>
            )}
            {!isProfileIncomplete && (
              <button
                onClick={handleUpdateInfo}
                className="rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900"
              >
                Chỉnh sửa
              </button>
            )}
            <button onClick={handleLogout} className="rounded-full border border-red-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-red-700 hover:border-red-500">
              Đăng xuất
            </button>
          </div>
        </header>

        {isProfileIncomplete && (
          <div className="mb-4 rounded-2xl border border-red-200 bg-red-50 p-4 text-sm text-red-700">
            <p className="font-semibold">Vui lòng cập nhật thông tin</p>
            <p className="mt-1">Thiếu: {missingFields.join(', ')}</p>
          </div>
        )}

        <section className="rounded-3xl border border-zinc-200 bg-white p-8 shadow-sm">
          <div className="flex flex-wrap items-center gap-4">
            {avatarUrl ? (
              <img src={avatarUrl} alt={displayName} className="h-20 w-20 rounded-full object-cover" />
            ) : (
              <div className="flex h-20 w-20 items-center justify-center rounded-full bg-zinc-900 text-xl font-bold text-white">
                {getInitials(displayName)}
              </div>
            )}

            <div>
              <p className="text-2xl font-semibold text-zinc-900">{displayName}</p>
              <p className="text-sm text-zinc-600">@{user?.username || 'unknown'}</p>
            </div>
          </div>

          {loading && <p className="mt-6 text-sm text-zinc-600">Đang tải thông tin tài khoản...</p>}
          {!loading && error && <p className="mt-6 rounded-2xl border border-amber-200 bg-amber-50 p-4 text-sm text-amber-800">{error}</p>}

          {isEditing && (
            <form onSubmit={handleSubmitUpdate} className="mt-6 rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">Cập nhật thông tin</p>
              <div className="mt-4 grid gap-4 md:grid-cols-2">
                <label className="text-sm text-zinc-700">
                  Họ tên
                  <input
                    name="fullName"
                    value={form.fullName}
                    onChange={handleChange}
                    className="mt-1 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm outline-none focus:border-zinc-900"
                    required
                  />
                </label>
                <label className="text-sm text-zinc-700">
                  Email
                  <input
                    type="email"
                    name="email"
                    value={form.email}
                    onChange={handleChange}
                    className="mt-1 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm outline-none focus:border-zinc-900"
                    required
                  />
                </label>
                <label className="text-sm text-zinc-700">
                  Số điện thoại
                  <input
                    name="phone"
                    value={form.phone}
                    onChange={handleChange}
                    className="mt-1 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm outline-none focus:border-zinc-900"
                    required
                  />
                </label>
                <label className="text-sm text-zinc-700">
                  Địa chỉ
                  <input
                    name="address"
                    value={form.address}
                    onChange={handleChange}
                    className="mt-1 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm outline-none focus:border-zinc-900"
                    required
                  />
                </label>
              </div>
              <div className="mt-4 flex items-center gap-2">
                <button
                  type="submit"
                  disabled={saving}
                  className="rounded-full bg-zinc-900 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-white hover:bg-zinc-700 disabled:cursor-not-allowed disabled:opacity-70"
                >
                  {saving ? 'Đang lưu...' : 'Lưu'}
                </button>
                <button
                  type="button"
                  onClick={handleCancelEdit}
                  disabled={saving}
                  className="rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900 disabled:cursor-not-allowed disabled:opacity-70"
                >
                  Hủy
                </button>
              </div>
            </form>
          )}

          <div className="mt-6 grid gap-4 md:grid-cols-2">
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Email</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.email || '-'}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Vai trò</p>
              <p className="mt-1 font-medium text-zinc-900">{String(user?.role || session?.role || '-').replace('ROLE_', '')}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Số điện thoại</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.phone || '-'}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Địa chỉ</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.address || '-'}</p>
            </div>
          </div>
        </section>
      </div>
    </div>
  )
}

export default UserProfilePage

import React, { useEffect, useMemo, useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import toast from 'react-hot-toast'
import { getCurrentUserDetail, updateCurrentUser } from '../services/authService'
import { clearAuth, getAuthSession } from '../services/sessionService'

function getInitials(name) {
  if (!name) return 'U'
  const parts = name.trim().split(/\s+/).filter(Boolean)
  if (parts.length === 0) return 'U'
  if (parts.length === 1) return parts[0].slice(0, 1).toUpperCase()
  return `${parts[0][0]}${parts[parts.length - 1][0]}`.toUpperCase()
}

function UserProfilePage() {
  const [session, setSession] = useState(() => getAuthSession())
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [userDetail, setUserDetail] = useState(null)
  const [isEditing, setIsEditing] = useState(false)
  const [saving, setSaving] = useState(false)
  const [form, setForm] = useState({
    fullName: '',
    email: '',
    phone: '',
    address: '',
  })
  const navigate = useNavigate()

  useEffect(() => {
    if (!session?.token) {
      navigate('/login', { replace: true })
      return
    }

    async function loadUserDetail() {
      setLoading(true)
      setError('')

      try {
        const detail = await getCurrentUserDetail()
        setUserDetail(detail)
        setForm({
          fullName: detail?.fullName || '',
          email: detail?.email || '',
          phone: detail?.phone || '',
          address: detail?.address || '',
        })
      } catch (err) {
        setError(err?.message || 'Không thể tải thông tin tài khoản')
      } finally {
        setLoading(false)
      }
    }

    loadUserDetail()
  }, [navigate, session?.token])

  const user = useMemo(() => {
    return userDetail ?? session?.user ?? null
  }, [session?.user, userDetail])

  const displayName = user?.fullName || user?.username || 'Tài khoản'
  const avatarUrl = user?.avatarUrl

  const missingFields = useMemo(() => {
    const checks = [
      { key: 'fullName', label: 'Họ tên' },
      { key: 'email', label: 'Email' },
      { key: 'phone', label: 'Số điện thoại' },
      { key: 'address', label: 'Địa chỉ' },
    ]

    return checks
      .filter(({ key }) => {
        const value = user?.[key]
        if (value === null || value === undefined) return true
        if (typeof value !== 'string') return false
        const normalized = value.trim()
        return normalized.length === 0 || normalized === '-'
      })
      .map(({ label }) => label)
  }, [user])

  const isProfileIncomplete = !loading && missingFields.length > 0

  const handleLogout = () => {
    clearAuth()
    toast.success('Đã đăng xuất')
    navigate('/login')
  }

  const handleUpdateInfo = () => {
    setIsEditing(true)
  }

  const handleChange = (event) => {
    const { name, value } = event.target
    setForm((prev) => ({ ...prev, [name]: value }))
  }

  const handleCancelEdit = () => {
    setForm({
      fullName: user?.fullName || '',
      email: user?.email || '',
      phone: user?.phone || '',
      address: user?.address || '',
    })
    setIsEditing(false)
  }

  const handleSubmitUpdate = async (event) => {
    event.preventDefault()

    const payload = {
      fullName: form.fullName.trim(),
      email: form.email.trim(),
      phone: form.phone.trim(),
      address: form.address.trim(),
    }

    if (!payload.fullName || !payload.email || !payload.phone || !payload.address) {
      toast.error('Vui lòng cập nhật thông tin')
      return
    }

    setSaving(true)
    try {
      const updated = await updateCurrentUser(payload)
      setUserDetail((prev) => ({ ...prev, ...updated }))
      setSession((prev) => {
        if (!prev) return prev
        return {
          ...prev,
          user: {
            ...(prev.user || {}),
            ...updated,
          },
        }
      })
      setIsEditing(false)
      toast.success('Cập nhật thông tin thành công')
    } catch (err) {
      toast.error(err?.message || 'Không thể cập nhật thông tin')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="min-h-screen bg-[linear-gradient(180deg,#f7f7f4_0%,#f4f4ef_45%,#ffffff_100%)] px-6 py-10">
      <div className="mx-auto w-full max-w-5xl">
        <header className="mb-8 flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">SplitGo</p>
            <h1 className="mt-2 text-3xl font-semibold tracking-tight text-zinc-900">Thông tin người dùng</h1>
          </div>
          <div className="flex items-center gap-3">
            <Link to="/products" className="rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900">
              Về sản phẩm
            </Link>
            {isProfileIncomplete && (
              <button
                onClick={handleUpdateInfo}
                className="rounded-full border border-amber-300 bg-amber-50 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-amber-800 hover:border-amber-500"
              >
                Cập nhật thông tin
              </button>
            )}
            {!isProfileIncomplete && (
              <button
                onClick={handleUpdateInfo}
                className="rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900"
              >
                Chỉnh sửa
              </button>
            )}
            <button onClick={handleLogout} className="rounded-full border border-red-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-red-700 hover:border-red-500">
              Đăng xuất
            </button>
          </div>
        </header>

        {isProfileIncomplete && (
          <div className="mb-4 rounded-2xl border border-red-200 bg-red-50 p-4 text-sm text-red-700">
            <p className="font-semibold">Vui lòng cập nhật thông tin</p>
            <p className="mt-1">Thiếu: {missingFields.join(', ')}</p>
          </div>
        )}

        <section className="rounded-3xl border border-zinc-200 bg-white p-8 shadow-sm">
          <div className="flex flex-wrap items-center gap-4">
            {avatarUrl ? (
              <img src={avatarUrl} alt={displayName} className="h-20 w-20 rounded-full object-cover" />
            ) : (
              <div className="flex h-20 w-20 items-center justify-center rounded-full bg-zinc-900 text-xl font-bold text-white">
                {getInitials(displayName)}
              </div>
            )}

            <div>
              <p className="text-2xl font-semibold text-zinc-900">{displayName}</p>
              <p className="text-sm text-zinc-600">@{user?.username || 'unknown'}</p>
            </div>
          </div>

          {loading && <p className="mt-6 text-sm text-zinc-600">Đang tải thông tin tài khoản...</p>}
          {!loading && error && <p className="mt-6 rounded-2xl border border-amber-200 bg-amber-50 p-4 text-sm text-amber-800">{error}</p>}

          {isEditing && (
            <form onSubmit={handleSubmitUpdate} className="mt-6 rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">Cập nhật thông tin</p>
              <div className="mt-4 grid gap-4 md:grid-cols-2">
                <label className="text-sm text-zinc-700">
                  Họ tên
                  <input
                    name="fullName"
                    value={form.fullName}
                    onChange={handleChange}
                    className="mt-1 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm outline-none focus:border-zinc-900"
                    required
                  />
                </label>
                <label className="text-sm text-zinc-700">
                  Email
                  <input
                    type="email"
                    name="email"
                    value={form.email}
                    onChange={handleChange}
                    className="mt-1 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm outline-none focus:border-zinc-900"
                    required
                  />
                </label>
                <label className="text-sm text-zinc-700">
                  Số điện thoại
                  <input
                    name="phone"
                    value={form.phone}
                    onChange={handleChange}
                    className="mt-1 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm outline-none focus:border-zinc-900"
                    required
                  />
                </label>
                <label className="text-sm text-zinc-700">
                  Địa chỉ
                  <input
                    name="address"
                    value={form.address}
                    onChange={handleChange}
                    className="mt-1 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm outline-none focus:border-zinc-900"
                    required
                  />
                </label>
              </div>
              <div className="mt-4 flex items-center gap-2">
                <button
                  type="submit"
                  disabled={saving}
                  className="rounded-full bg-zinc-900 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-white hover:bg-zinc-700 disabled:cursor-not-allowed disabled:opacity-70"
                >
                  {saving ? 'Đang lưu...' : 'Lưu'}
                </button>
                <button
                  type="button"
                  onClick={handleCancelEdit}
                  disabled={saving}
                  className="rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900 disabled:cursor-not-allowed disabled:opacity-70"
                >
                  Hủy
                </button>
              </div>
            </form>
          )}

          <div className="mt-6 grid gap-4 md:grid-cols-2">
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Họ tên</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.fullName || '-'}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Tên đăng nhập</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.username || '-'}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Email</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.email || '-'}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Vai trò</p>
              <p className="mt-1 font-medium text-zinc-900">{String(user?.role || session?.role || '-').replace('ROLE_', '')}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Số điện thoại</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.phone || '-'}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Địa chỉ</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.address || '-'}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4 md:col-span-2">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Cập nhật lần cuối</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.updatedAt || '-'}</p>
            </div>
          </div>
        </section>
      </div>
    </div>
  )
}

export default UserProfilePage

import { parseApiResponse, request } from './apiClient'

export async function getCategories() {
  const response = await request('/categories')
  const payload = await parseApiResponse(response)
  return Array.isArray(payload?.data) ? payload.data : []
}
